const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x172554);this.cannon=this.add.rectangle(40,H-40,22,22,0x93c5fd);this.target=this.add.rectangle(W-40,60,24,24,0xfca5a5);this.bul=this.physics.add.group();this.wind=0;this.ui=this.add.text(10,10,'Wind:0');this.input.on('pointerdown',p=>this.fire(p));this.time.addEvent({delay:1500,loop:true,callback:()=>{this.wind=Phaser.Math.Between(-40,40);this.ui.setText('Wind:'+this.wind);}});this.r=this.input.keyboard.addKey('R');this.physics.add.overlap(this.bul,this.target,()=>this.hit());}fire(p){if(this.over)return;const b=this.add.circle(this.cannon.x,this.cannon.y,6,0xfef08a);this.physics.add.existing(b);const a=Phaser.Math.Angle.Between(this.cannon.x,this.cannon.y,p.x,p.y);b.body.setVelocity(Math.cos(a)*230,Math.sin(a)*230);b.body.setGravityY(120);b.wind=this.wind;this.bul.add(b);}hit(){if(this.over)return;this.over=true;this.add.text(W/2,H/2,'HIT! R').setOrigin(.5);}update(){if(this.r.isDown)this.scene.restart();this.bul.getChildren().forEach(b=>{b.body.velocity.x+=b.wind*0.01;if(b.y>H+20||b.x>W+20||b.x<-20)b.destroy();});}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});
